import unittest

from metrics import mean, median


class Acceptance(unittest.TestCase):
    def test_mean_preserved(self): self.assertEqual(mean([2, 4]), 3)
    def test_odd(self): self.assertEqual(median([9, 1, 4]), 4)
    def test_even(self): self.assertEqual(median([1, 2, 8, 9]), 5)
    def test_input_unchanged(self):
        values = [3, 1, 2]
        median(values)
        self.assertEqual(values, [3, 1, 2])
    def test_empty(self):
        with self.assertRaises(ValueError): median([])


if __name__ == "__main__": unittest.main()
